    """
    # 订阅地址可在函数参数或环境变量中配置，此处占位
    RSS_URL = ""  # <-- 稍后由用户提供

    if not RSS_URL:
        return {"events": [], "next_cursor": last_cursor or ""}

    feed = feedparser.parse(RSS_URL)
    if feed.bozo and not feed.entries:
        # 解析失败但无条目，静默返回
        return {"events": [], "next_cursor": last_cursor or ""}

    new_events = []
    latest_pub = last_cursor or ""

    for entry in feed.entries:
        # 使用 published_parsed 或 updated_parsed 作为时间戳
        pub_time = entry.get("published_parsed") or entry.get("updated_parsed")
        if not pub_time:
            continue

        # 转换为 ISO 格式字符串作为 cursor
        pub_ts = datetime(*pub_time[:6], tzinfo=timezone.utc).isoformat()

        # 如果是新的（大于 last_cursor），才纳入
        if not last_cursor or pub_ts > last_cursor:
