                "title": entry.get("title", ""),
                "link": entry.get("link", ""),
                "published": pub_ts,
                "summary": entry.get("summary", ""),
            })

        # 更新最新的发布时间
        if pub_ts > latest_pub:
            latest_pub = pub_ts

    return {
        "events": new_events,
        "next_cursor": latest_pub,
