from typing import Optional

def poll(last_cursor: Optional[str] = None) -> dict:
    """
    轮询 RSS 订阅源，基于 cursor 避免重复触发。

    last_cursor: 上次处理的最新条目 id (如 guid/link)，首次为 None

    Returns:
        {"events": [...], "next_cursor": str}
    """
    # 订阅地址——后续可通过环境变量或配置替换
    rss_url = "YOUR_RSS_URL_HERE"

    feed = feedparser.parse(rss_url)
    entries = feed.entries  # 按发布时间降序通常

    if not entries:
        return {"events": [], "next_cursor": last_cursor or ""}

    # 用 guid 或 link 作为 cursor
    latest_id = entries[0].get("id") or entries[0].get("link", "")

    if last_cursor is None:
        # 首次运行：只记录 cursor，不输出 events（或首次全量输出，视需要而定）
        return {"events": [], "next_cursor": latest_id}

    # 找到上一次 cursor 的位置，只取新条目
    new_events = []
    for entry in entries:
        entry_id = entry.get("id") or entry.get("link", "")
        if entry_id == last_cursor:
            break  # 遇到已处理过的条目，停止
        new_events.append({
            "title": entry.get("title", ""),
            "link": entry.get("link", ""),
            "published": entry.get("published", ""),
            "summary": entry.get("summary", ""),
            "id": entry_id,
        })

    # 新条目按时间升序排列（从旧到新），方便下游顺序处理
    new_events.reverse()

    return {
        "events": new_events,
        "next_cursor": latest_id,
    }
