from datetime import datetime, timezone

# TODO: 将下面的 URL 替换为你的实际 RSS 订阅地址
RSS_URL = "YOUR_RSS_URL_HERE"


def poll(last_cursor=None):
    """
    轮询 RSS 订阅源，基于 cursor 增量返回新条目，防止重复触发。

    Args:
        last_cursor: 上次处理的最新条目发布时间戳（int），首次调用为 None。

    Returns:
        dict: {"events": [...], "next_cursor": int|None}
            - events: 新增的条目列表（按时间从旧到新排列）
            - next_cursor: 最新一条的时间戳，供下次轮询使用
    """
    feed = feedparser.parse(RSS_URL)

    if not feed.entries:
        return {"events": [], "next_cursor": last_cursor}

    new_events = []
    next_cursor = last_cursor

    # 从旧到新遍历，确保事件顺序正确
    for entry in reversed(feed.entries):
        # 尝试解析发布时间，作为 cursor 的依据
        try:
            parsed = entry.published_parsed
            ts = int(datetime(*parsed[:6], tzinfo=timezone.utc).timestamp())
        except (AttributeError, TypeError, ValueError):
            # 如果没有发布时间字段，跳过该条目
            continue

        if last_cursor is None or ts > last_cursor:
            new_events.append({
                "title": entry.get("title", ""),
                "link": entry.get("link", ""),
                "published": entry.get("published", ""),
                "published_ts": ts,
                "summary": entry.get("summary", ""),
                "id": entry.get("id") or entry.get("link", ""),
            })
            if next_cursor is None or ts > next_cursor:
                next_cursor = ts

    return {"events": new_events, "next_cursor": next_cursor}
